-- seed-admin-bdys.sql — Raw admin boundary fixtures for spatial join testing (E1.10)
--
-- These tables mirror the raw_admin_bdys schema that shp2pgsql normally populates
-- from Admin Boundary shapefiles. The geometries are tiny rectangular buffers around
-- each fixture address point, grouped by boundary assignment. This ensures the spatial
-- join in address_full_prep.sql derives the same boundary assignments as the original
-- gnaf-loader boundary tagging.
--
-- The prep SQL (fixtures/prep-admin-bdys.sql) transforms these raw tables into the
-- admin_bdys boundary tables used by the spatial join fallback.
--
-- Generated from: address_principal_admin_boundaries + address_principals.geom
-- Buffer size: 0.00005 degrees (~5.5m) rectangular expand per address point
-- Coordinate precision: snapped to 0.000001 degree grid (~0.11m)

SET search_path TO public;
DROP SCHEMA IF EXISTS raw_admin_bdys_202602 CASCADE;
CREATE SCHEMA raw_admin_bdys_202602;

CREATE TABLE IF NOT EXISTS raw_admin_bdys_202602.aus_state (state_pid text PRIMARY KEY, st_abbrev text NOT NULL);
CREATE TABLE IF NOT EXISTS raw_admin_bdys_202602.aus_comm_electoral (ce_pid text PRIMARY KEY, name text NOT NULL, state_pid text NOT NULL, dt_gazetd text);
CREATE TABLE IF NOT EXISTS raw_admin_bdys_202602.aus_comm_electoral_polygon (gid integer PRIMARY KEY, ce_pid text NOT NULL, geom geometry(MultiPolygon, 7844) NOT NULL);
CREATE TABLE IF NOT EXISTS raw_admin_bdys_202602.aus_lga (gid integer PRIMARY KEY, lga_pid text NOT NULL, abb_name text, lga_name text NOT NULL, state text NOT NULL, geom geometry(MultiPolygon, 7844) NOT NULL);
CREATE TABLE IF NOT EXISTS raw_admin_bdys_202602.aus_wards (gid integer PRIMARY KEY, ward_pid text NOT NULL, lga_pid text NOT NULL, ward_name text NOT NULL, state text NOT NULL, geom geometry(MultiPolygon, 7844) NOT NULL);
CREATE TABLE IF NOT EXISTS raw_admin_bdys_202602.aus_state_electoral_class_aut (code text PRIMARY KEY, name text NOT NULL);
CREATE TABLE IF NOT EXISTS raw_admin_bdys_202602.aus_state_electoral (se_pid text PRIMARY KEY, name text NOT NULL, dt_gazetd text, eff_start timestamp DEFAULT now(), eff_end timestamp DEFAULT NULL, secl_code text NOT NULL, state_pid text NOT NULL);
CREATE TABLE IF NOT EXISTS raw_admin_bdys_202602.aus_state_electoral_polygon (gid integer PRIMARY KEY, se_pid text NOT NULL, geom geometry(MultiPolygon, 7844) NOT NULL);
